const AUTH = 'Basic ' + Buffer.from(`:${process.env.AZURE_DEVOPS_PAT}`).toString('base64');

// ── ADO REST helper ───────────────────────────────────────────────────────────
function adoRequest(method, urlPath, body) {
    return new Promise((resolve, reject) => {
        const bodyStr = body ? JSON.stringify(body) : null;
        const headers = { Authorization: AUTH, 'Content-Type': 'application/json', Accept: 'application/json' };
        if (bodyStr) headers['Content-Length'] = Buffer.byteLength(bodyStr).toString();
        const req = https.request(
            { hostname: 'dev.azure.com', path: urlPath, method, headers },
            res => {
                let raw = '';
                res.on('data', c => { raw += c; });
                res.on('end', () => {
                    try { resolve({ status: res.statusCode, body: raw ? JSON.parse(raw) : null }); }
                    catch { resolve({ status: res.statusCode, body: raw }); }
                });
            }
        );
        req.on('error', reject);
        if (bodyStr) req.write(bodyStr);
        req.end();
    });
}

async function getLatestCommitId() {
    const url =
        `/${ORG}/${encodeURIComponent(PROJECT)}/_apis/git/repositories/${encodeURIComponent(REPO)}` +
        `/refs?filter=heads%2F${encodeURIComponent(BRANCH)}&api-version=${API_VER}`;
    const res = await adoRequest('GET', url, null);
    if (res.status !== 200 || !res.body?.value?.[0]) {
        throw new Error(`Could not get latest commit — HTTP ${res.status}: ${JSON.stringify(res.body)}`);
    }
    return res.body.value[0].objectId;
}

