/** Read a local source file and return its content encoded as base64. */
function fileToBase64(relativePath) {
    const full = path.join(__dirname, relativePath);
    if (!fs.existsSync(full)) throw new Error(`Source file not found: ${full}`);
    return fs.readFileSync(full).toString('base64');
}

/** Build a base64-encoded string from a plain text literal. */
function textToBase64(text) {
    return Buffer.from(text, 'utf-8').toString('base64');
}

const README_MD = `# Arun — Azure Blob Storage Database Layer

This folder contains the database-related source code for the
**Weekend Support Tracker** application, migrated from Render PostgreSQL
to **Azure Blob Storage**.

## Folder structure

\`\`\`
Arun/
  README.md               — This file
  db/
    connection.js         — Azure Blob Storage client factory (auth setup)
    repository.js         — Data access layer: loadData() / saveData()
    models.js             — Schema factories & validation helpers
  scripts/
    migrate.js            — One-time migration: local data.json → Azure Blob
  config/
    azure-env.example     — Required environment variable reference
\`\`\`

## Quick start

### 1. Create an Azure Storage Account
\`\`\`bash
az storage account create \\
  --name weekendsupporttracker \\
  --resource-group <your-rg> \\
  --sku Standard_LRS \\
  --kind StorageV2
\`\`\`

### 2. Get the connection string
\`\`\`bash
az storage account show-connection-string \\
  --name weekendsupporttracker \\
  --resource-group <your-rg> \\
  --query connectionString -o tsv
\`\`\`

### 3. Configure the application
Set the connection string as the \`AZURE_STORAGE_CONNECTION_STRING\`
environment variable in Render (or your hosting platform).

### 4. Run the migration (one time only)
\`\`\`bash
cd backend
AZURE_STORAGE_CONNECTION_STRING="<your-conn-str>" node azure/migrate.js --dry-run
AZURE_STORAGE_CONNECTION_STRING="<your-conn-str>" node azure/migrate.js
\`\`\`

## Security
- Store the connection string exclusively in environment variables / Azure Key Vault
- Never commit secrets to this repository
- The container is private by default — no public blob access
`;

